@@ -692,10 +692,30 @@ app.post('/api/pause/:agent', (req, res) => {
   } catch (e) {
     return res.status(500).json({ error: `failed to write pause flag: ${e.message}` });
   }
-  execFile('/usr/local/bin/hive', ['stop', agent], { timeout: 30000 }, (err) => {
